import java.util.Scanner;

public class SecureBufferUsage {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine(); // Read the entire line

        // Limit the buffer size to avoid buffer overflow
        int bufferSize = Math.min(userInput.length(), 10);
        byte[] buffer = new byte[bufferSize];

        // Copy only up to bufferSize bytes from userInput
        System.arraycopy(userInput.getBytes(), 0, buffer, 0, bufferSize);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

